  1→import { type ReactNode, useCallback, useMemo, useState } from 'react';
  2→import {
  3→  CATEGORY_LABELS,
  4→  type LayoutCategory,
  5→  WINDOW_LAYOUTS,
  6→  getLayoutIcon,
  7→} from '../../data/window_layouts_data';
  8→import { useHUD } from '../../hooks/use_hud';
  9→import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
 10→import { useNavigation } from '../../hooks/use_navigation';
