 76→const FILTER_SECTIONS: SearchDropdownSection[] = [
 77→  {
 78→    options: [
 79→      {
 80→        label: 'All',
 81→        value: 'all',
 82→      },
 83→    ],
 84→  },
 85→  {
 86→    title: 'Category',
 87→    options: [
