 89→        label: 'Halves',
 90→        value: 'halves',
 91→      },
 92→      {
 93→        label: 'Thirds',
 94→        value: 'thirds',
 95→      },
 96→      {
 97→        label: 'Quarters',
 98→        value: 'quarters',
 99→      },
100→      {
101→        label: 'Other',
102→        value: 'other',
103→      },
