108→export function WindowManagementView() {
109→  const nav = useNavigation();
110→  const [query, setQuery] = useState('');
111→  const [filterValue, setFilterValue] = useState('all');
112→  const [selectedIndex, setSelectedIndex] = useState(0);
113→  const [actionsOpen, setActionsOpen] = useState(false);
114→  const { items: hudItems, show: showHUD } = useHUD();
115→
116→  const filtered = useMemo(() => {
117→    let items = WINDOW_LAYOUTS;
118→    if (filterValue !== 'all') {
119→      items = items.filter(l => l.category === filterValue);
120→    }
121→    if (query) {
122→      items = items.filter(l => fuzzyMatch(query, l.name));
123→    }
124→    return items;
125→  }, [
126→    query,
127→    filterValue,
128→  ]);
129→
130→  const groupedByCategory = useMemo(() => {
131→    const groups: {
132→      category: LayoutCategory;
133→      items: typeof filtered;
134→    }[] = [];
135→    const seen = new Set<LayoutCategory>();
136→    for (const item of filtered) {
137→      if (!seen.has(item.category)) {
138→        seen.add(item.category);
139→        groups.push({
140→          category: item.category,
141→          items: filtered.filter(l => l.category === item.category),
142→        });
143→      }
144→    }
145→    return groups;
146→  }, [filtered]);
147→
148→  const flatItems = useMemo(() => filtered, [filtered]);
149→  const totalItemCount = flatItems.length;
150→
151→  const selectedLayout = flatItems[selectedIndex];
152→
153→  const handleQueryChange = useCallback((value: string) => {
154→    setQuery(value);
155→    setSelectedIndex(0);
156→    setActionsOpen(false);
157→  }, []);
158→
159→  const handleFilterChange = useCallback((value: string) => {
160→    setFilterValue(value);
161→    setSelectedIndex(0);
162→  }, []);
163→
164→  const handleActiveIndexChange = useCallback((index: number) => {
165→    setSelectedIndex(index);
166→    setActionsOpen(false);
167→  }, []);
168→
169→  const handleApply = useCallback(() => {
170→    if (!selectedLayout) return;
171→    setActionsOpen(false);
172→    showHUD({
173→      icon: <ApplyHUDIcon />,
174→      title: `Applied ${selectedLayout.name}`,
175→    });
176→  }, [
177→    selectedLayout,
178→    showHUD,
179→  ]);
180→
181→  const handleCopyName = useCallback(() => {
182→    if (!selectedLayout) return;
183→    setActionsOpen(false);
184→    performCopy(selectedLayout.name, showHUD);
185→  }, [
186→    selectedLayout,
187→    showHUD,
188→  ]);
189→
190→  const toggleActions = useCallback(() => {
191→    setActionsOpen(prev => !prev);
192→  }, []);
193→
194→  const closeActions = useCallback(() => {
195→    setActionsOpen(false);
196→  }, []);
197→
198→  useKeyboardShortcut(
199→    {
200→      key: 'k',
201→      meta: true,
202→    },
203→    toggleActions,
204→  );
205→  useKeyboardShortcut(
206→    {
207→      key: 'c',
208→      meta: true,
209→    },
210→    handleCopyName,
211→  );
212→
213→  const dropdownSections: DropdownSection[] = useMemo(
214→    () => [
215→      {
216→        title: 'Actions',
217→        actions: [
218→          {
219→            label: 'Apply Layout',
220→            shortcut: <Kbd keys={['↵']} />,
221→            onClick: handleApply,
222→          },
223→          createCopyAction(
224→            {
225→              content: selectedLayout?.name ?? '',
226→              title: 'Copy Name',
227→              shortcut: (
228→                <Kbd
229→                  keys={[
230→                    '⌘',
231→                    'C',
232→                  ]}
233→                />
234→              ),
235→            },
236→            showHUD,
237→          ),
238→        ],
239→      },
240→    ],
241→    [
242→      selectedLayout?.name,
243→      handleApply,
244→      showHUD,
245→    ],
246→  );
247→
248→  const activeDescendantId =
249→    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;
250→
251→  function renderLayoutItem(
252→    layout: (typeof WINDOW_LAYOUTS)[number],
253→    idx: number,
254→  ): ReactNode {
255→    return (
256→      <ListItem
257→        key={layout.id}
258→        index={idx}
259→        icon={getLayoutIcon(layout)}
260→        title={layout.name}
261→        accessories={[
262→          {
263→            tag: {
264→              text: CATEGORY_LABELS[layout.category],
265→              color:
266→                layout.category === 'halves'
267→                  ? 'blue'
268→                  : layout.category === 'thirds'
269→                    ? 'green'
270→                    : layout.category === 'quarters'
271→                      ? 'orange'
272→                      : 'purple',
273→            },
274→          },
275→          {
276→            icon: <Kbd keys={layout.shortcutKeys} />,
277→          },
278→        ]}
279→        query={query || undefined}
280→      />
281→    );
282→  }
283→
284→  return (
285→    <>
286→      <SearchBar
287→        value={query}
288→        onChange={handleQueryChange}
289→        placeholder="Search Layouts..."
290→        activeDescendantId={activeDescendantId}
291→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
292→        dropdown={
293→          <SearchDropdown
294→            sections={FILTER_SECTIONS}
295→            value={filterValue}
296→            onChange={handleFilterChange}
297→          />
298→        }
299→      />
300→      <div className="command-palette__body">
301→        <div className="command-palette__list-container">
302→          {totalItemCount === 0 ? (
303→            <EmptyState
304→              icon={<SearchEmptyIcon />}
305→              title="No Layouts Found"
306→              description="Try a different search term or filter"
307→            />
308→          ) : (
309→            <List
310→              itemCount={totalItemCount}
311→              onActiveIndexChange={handleActiveIndexChange}
312→              onAction={handleApply}
313→            >
314→              {(() => {
315→                let globalIndex = 0;
316→                return groupedByCategory.map(group => (
317→                  <ListSection
318→                    key={group.category}
319→                    title={CATEGORY_LABELS[group.category]}
320→                  >
321→                    {group.items.map(layout =>
322→                      renderLayoutItem(layout, globalIndex++))}
323→                  </ListSection>
324→                ));
325→              })()}
326→            </List>
327→          )}
328→        </div>
329→      </div>
330→      <ActionPanel
331→        contextLabel="Window Management"
332→        actions={[
333→          {
334→            label: 'Apply Layout',
335→            shortcut: <Kbd keys={['↵']} />,
336→          },
337→          {
338→            label: 'Actions',
339→            shortcut: (
340→              <Kbd
341→                keys={[
342→                  '⌘',
343→                  'K',
344→                ]}
345→              />
346→            ),
347→            onClick: toggleActions,
348→          },
349→        ]}
350→        dropdownOpen={actionsOpen}
351→        dropdownSections={dropdownSections}
352→        onDropdownClose={closeActions}
353→      />
354→      <HUDContainer items={hudItems} />
355→    </>
356→  );
357→}
