  1→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  2→import type { EmojiCategory, EmojiEntry } from '../../data/emoji_data';
  3→import {
  4→  EMOJI_CATEGORIES,
  5→  EMOJI_CATEGORY_LABELS,
  6→  EMOJI_CATEGORY_ORDER,
  7→  MOCK_EMOJIS,
  8→} from '../../data/emoji_data';
  9→import { useHUD } from '../../hooks/use_hud';
 10→import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
 11→import { useNavigation } from '../../hooks/use_navigation';
 12→import { fuzzyMatch } from '../../utils/fuzzy_search';
 13→import { isStringArray, storageGet, storageSet } from '../../utils/storage';
 14→import { ActionPanel } from '../action_panel/action_panel';
 15→import { createCopyAction, performCopy } from '../action_panel/actions';
 16→import type { DropdownSection } from '../action_panel/actions_dropdown';
 17→import { EmptyState } from '../empty_state/empty_state';
 18→import { HUDContainer } from '../hud/hud_container';
 19→import { Kbd } from '../kbd/kbd';
 20→import { SearchBar } from '../search_bar/search_bar';
 21→import type { SearchDropdownSection } from '../search_bar/search_dropdown';
 22→import { SearchDropdown } from '../search_bar/search_dropdown';
 23→import './emoji_picker_view.scss';
 24→
 25→const COLUMNS = 6;
 26→const STORAGE_KEY = 'emoji-recent';
 27→const MAX_RECENT = 12;
 28→
 29→function SearchEmptyIcon() {
 30→  return (
 31→    <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
 32→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
 33→      <line
 34→        x1="30"
 35→        y1="30"
 36→        x2="42"
 37→        y2="42"
 38→        stroke="currentColor"
 39→        strokeWidth="3"
 40→        strokeLinecap="round"
 41→      />
 42→    </svg>
 43→  );
 44→}
 45→
 46→function loadRecentEmojis(): string[] {
 47→  const stored = storageGet(STORAGE_KEY, isStringArray);
 48→  if (stored) return stored;
 49→
 50→  try {
 51→    const legacy = localStorage.getItem('emoji-picker-recent');
 52→    if (legacy) {
 53→      const parsed: unknown = JSON.parse(legacy);
 54→      if (isStringArray(parsed)) {
 55→        storageSet(STORAGE_KEY, parsed);
 56→        localStorage.removeItem('emoji-picker-recent');
 57→        return parsed;
 58→      }
 59→    }
 60→  } catch {
 61→    // unavailable
 62→  }
 63→  return [];
 64→}
 65→
 66→interface EmojiSection {
 67→  title: string;
 68→  emojis: EmojiEntry[];
 69→}
 70→
 71→const FILTER_SECTIONS: SearchDropdownSection[] = [
 72→  {
 73→    options: [
 74→      {
 75→        label: 'All',
 76→        value: 'all',
 77→      },
 78→    ],
 79→  },
 80→  {
 81→    title: 'Category',
 82→    options: EMOJI_CATEGORIES.map(c => ({
 83→      label: c.label,
 84→      value: c.value,
 85→    })),
 86→  },
 87→];
 88→
 89→export function EmojiPickerView() {
 90→  const nav = useNavigation();
 91→  const [query, setQuery] = useState('');
 92→  const [filterValue, setFilterValue] = useState('all');
 93→  const [activeIndex, setActiveIndex] = useState(0);
 94→  const [actionsOpen, setActionsOpen] = useState(false);
 95→  const [recentChars, setRecentChars] = useState<string[]>(loadRecentEmojis);
 96→  const { items: hudItems, show: showHUD } = useHUD();
 97→  const containerRef = useRef<HTMLDivElement>(null);
 98→
 99→  const emojiLookup = useMemo(() => {
100→    const map = new Map<string, EmojiEntry>();
101→    for (const e of MOCK_EMOJIS) {
102→      map.set(e.char, e);
103→    }
104→    return map;
105→  }, []);
106→
107→  const recentEmojis = useMemo(
108→    () =>
109→      recentChars
110→        .map(char => emojiLookup.get(char))
111→        .filter((e): e is EmojiEntry => e !== undefined),
112→    [
113→      recentChars,
114→      emojiLookup,
115→    ],
116→  );
117→
118→  const filtered = useMemo(() => {
119→    let emojis = MOCK_EMOJIS;
120→    if (filterValue !== 'all') {
121→      emojis = emojis.filter(e => e.category === filterValue);
122→    }
123→    if (query) {
124→      emojis = emojis.filter(
125→        e =>
126→          fuzzyMatch(query, e.name) ||
127→          e.keywords.some(k => fuzzyMatch(query, k)) ||
128→          e.char === query,
129→      );
130→    }
131→    return emojis;
132→  }, [
133→    query,
134→    filterValue,
135→  ]);
136→
137→  const sections = useMemo(() => {
138→    const result: EmojiSection[] = [];
139→
140→    if (!query && filterValue === 'all' && recentEmojis.length > 0) {
141→      result.push({
142→        title: 'Recently Used',
143→        emojis: recentEmojis,
144→      });
145→    }
146→
147→    const grouped = new Map<EmojiCategory, EmojiEntry[]>();
148→    for (const emoji of filtered) {
149→      const existing = grouped.get(emoji.category);
150→      if (existing) {
151→        existing.push(emoji);
152→      } else {
153→        grouped.set(emoji.category, [emoji]);
154→      }
155→    }
156→
157→    for (const cat of EMOJI_CATEGORY_ORDER) {
158→      const items = grouped.get(cat);
159→      if (items && items.length > 0) {
160→        result.push({
161→          title: EMOJI_CATEGORY_LABELS[cat],
162→          emojis: items,
163→        });
164→      }
165→    }
166→
167→    return result;
168→  }, [
169→    filtered,
170→    query,
171→    filterValue,
172→    recentEmojis,
173→  ]);
174→
175→  const flatEmojis = useMemo(() => sections.flatMap(s => s.emojis), [sections]);
176→  const totalCount = flatEmojis.length;
177→
178→  useEffect(() => {
179→    if (totalCount === 0) {
180→      setActiveIndex(0);
181→    } else if (activeIndex >= totalCount) {
182→      setActiveIndex(totalCount - 1);
183→    }
184→  }, [
185→    totalCount,
186→    activeIndex,
187→  ]);
188→
189→  useEffect(() => {
190→    const container = containerRef.current;
191→    if (!container) return;
192→    const el = container.querySelector<HTMLElement>(
193→      `[data-emoji-index="${activeIndex}"]`,
194→    );
195→    el?.scrollIntoView({ block: 'nearest' });
196→  }, [activeIndex]);
197→
198→  const selectedEmoji = flatEmojis[activeIndex];
199→
200→  const addToRecent = useCallback((char: string) => {
201→    setRecentChars(prev => {
202→      const next = [
203→        char,
204→        ...prev.filter(c => c !== char),
205→      ].slice(0, MAX_RECENT);
206→      storageSet(STORAGE_KEY, next);
207→      return next;
208→    });
209→  }, []);
210→
211→  const handleCopyEmoji = useCallback(
212→    (emoji?: EmojiEntry) => {
213→      const target = emoji ?? selectedEmoji;
214→      if (!target) return;
215→      setActionsOpen(false);
216→      performCopy(target.char, showHUD, {
217→        hudTitle: `Copied ${target.char}`,
218→        onCopy: () => addToRecent(target.char),
219→      });
220→    },
221→    [
222→      selectedEmoji,
223→      showHUD,
224→      addToRecent,
225→    ],
226→  );
227→
228→  const handleQueryChange = useCallback((value: string) => {
229→    setQuery(value);
230→    setActiveIndex(0);
231→    setActionsOpen(false);
232→  }, []);
233→
234→  const handleFilterChange = useCallback((value: string) => {
235→    setFilterValue(value);
236→    setActiveIndex(0);
237→  }, []);
238→
239→  const toggleActions = useCallback(() => {
240→    setActionsOpen(prev => !prev);
241→  }, []);
242→
243→  const closeActions = useCallback(() => {
244→    setActionsOpen(false);
245→  }, []);
246→
247→  useKeyboardShortcut(
248→    {
249→      key: 'k',
250→      meta: true,
251→    },
252→    toggleActions,
253→  );
254→  useKeyboardShortcut(
255→    {
256→      key: 'c',
257→      meta: true,
258→    },
259→    () => handleCopyEmoji(),
260→  );
261→
262→  useEffect(() => {
263→    function handleKeyDown(e: KeyboardEvent) {
264→      if (totalCount === 0) return;
265→      if (actionsOpen) return;
266→      if (e.metaKey || e.ctrlKey || e.altKey) return;
267→
268→      const isTextInput =
269→        e.target instanceof HTMLInputElement ||
270→        e.target instanceof HTMLTextAreaElement;
271→
272→      switch (e.key) {
273→        case 'ArrowRight': {
274→          if (isTextInput) return;
275→          e.preventDefault();
276→          setActiveIndex(prev => (prev + 1 < totalCount ? prev + 1 : 0));
277→          break;
278→        }
279→        case 'ArrowLeft': {
280→          if (isTextInput) return;
281→          e.preventDefault();
282→          setActiveIndex(prev => (prev - 1 >= 0 ? prev - 1 : totalCount - 1));
283→          break;
284→        }
285→        case 'ArrowDown': {
286→          e.preventDefault();
287→          setActiveIndex(prev => {
288→            const sectionInfo = getSectionInfo(prev);
289→            if (!sectionInfo) return prev;
290→            const { sectionStart, sectionLength } = sectionInfo;
291→            const posInSection = prev - sectionStart;
292→            const row = Math.floor(posInSection / COLUMNS);
293→            const col = posInSection % COLUMNS;
294→            const sectionRows = Math.ceil(sectionLength / COLUMNS);
295→
296→            if (row + 1 < sectionRows) {
297→              const nextIdx = sectionStart + (row + 1) * COLUMNS + col;
298→              return nextIdx < sectionStart + sectionLength
299→                ? nextIdx
300→                : sectionStart + sectionLength - 1;
301→            }
302→
303→            const nextSectionStart = sectionStart + sectionLength;
304→            if (nextSectionStart < totalCount) {
305→              const nextInfo = getSectionInfo(nextSectionStart);
306→              if (!nextInfo) return prev;
307→              const targetIdx = nextSectionStart + col;
308→              return targetIdx < nextSectionStart + nextInfo.sectionLength
309→                ? targetIdx
310→                : nextSectionStart + nextInfo.sectionLength - 1;
311→            }
312→
313→            return prev;
314→          });
315→          break;
316→        }
317→        case 'ArrowUp': {
318→          e.preventDefault();
319→          setActiveIndex(prev => {
320→            const sectionInfo = getSectionInfo(prev);
321→            if (!sectionInfo) return prev;
322→            const { sectionStart } = sectionInfo;
323→            const posInSection = prev - sectionStart;
324→            const row = Math.floor(posInSection / COLUMNS);
325→            const col = posInSection % COLUMNS;
326→
327→            if (row > 0) {
328→              return sectionStart + (row - 1) * COLUMNS + col;
329→            }
330→
331→            if (sectionStart > 0) {
332→              const prevSectionEnd = sectionStart - 1;
333→              const prevInfo = getSectionInfo(prevSectionEnd);
334→              if (!prevInfo) return prev;
335→              const prevSectionRows = Math.ceil(
336→                prevInfo.sectionLength / COLUMNS,
337→              );
338→              const lastRowStart =
339→                prevInfo.sectionStart + (prevSectionRows - 1) * COLUMNS;
340→              const targetIdx = lastRowStart + col;
341→              return targetIdx < prevInfo.sectionStart + prevInfo.sectionLength
342→                ? targetIdx
343→                : prevInfo.sectionStart + prevInfo.sectionLength - 1;
344→            }
345→
346→            return prev;
347→          });
348→          break;
349→        }
350→        case 'Enter': {
351→          e.preventDefault();
352→          handleCopyEmoji();
353→          break;
354→        }
355→      }
356→    }
357→
358→    window.addEventListener('keydown', handleKeyDown);
359→    return () => window.removeEventListener('keydown', handleKeyDown);
360→  }, [
361→    totalCount,
362→    actionsOpen,
363→    handleCopyEmoji,
364→    sections,
365→  ]);
366→
367→  const sectionBoundaries = useMemo(() => {
368→    const boundaries: {
369→      start: number;
370→      length: number;
371→    }[] = [];
372→    let offset = 0;
373→    for (const section of sections) {
374→      boundaries.push({
375→        start: offset,
376→        length: section.emojis.length,
377→      });
378→      offset += section.emojis.length;
379→    }
380→    return boundaries;
381→  }, [sections]);
382→
383→  function getSectionInfo(index: number) {
384→    for (const b of sectionBoundaries) {
385→      if (index >= b.start && index < b.start + b.length) {
386→        return {
387→          sectionStart: b.start,
388→          sectionLength: b.length,
389→        };
390→      }
391→    }
392→    return null;
393→  }
394→
395→  const dropdownSections: DropdownSection[] = useMemo(
396→    () => [
397→      {
398→        title: 'Actions',
399→        actions: [
400→          createCopyAction(
401→            {
