121→  const filtered = useMemo(() => {
122→    let items = entries;
123→    if (filterValue !== 'all') {
124→      items = items.filter(e => e.fileType === filterValue);
125→    }
126→    if (query) {
127→      items = items.filter(
128→        e => fuzzyMatch(query, e.name) || fuzzyMatch(query, e.path),
129→      );
130→    }
131→    return items;
132→  }, [
133→    entries,
134→    query,
135→    filterValue,
136→  ]);
137→
138→  const folders = useMemo(
139→    () => filtered.filter(e => e.fileType === 'folder'),
140→    [filtered],
141→  );
142→  const files = useMemo(
143→    () => filtered.filter(e => e.fileType !== 'folder'),
144→    [filtered],
145→  );
146→  const totalItemCount = filtered.length;
147→
148→  const flatItems = useMemo(
149→    () => [
150→      ...folders,
151→      ...files,
152→    ],
153→    [
154→      folders,
155→      files,
156→    ],
157→  );
158→
159→  useEffect(() => {
160→    if (selectedIndex >= totalItemCount && totalItemCount > 0) {
161→      setSelectedIndex(totalItemCount - 1);
162→    } else if (totalItemCount === 0) {
163→      setSelectedIndex(0);
164→    }
165→  }, [
166→    selectedIndex,
167→    totalItemCount,
168→  ]);
169→
170→  const selectedEntry = flatItems[selectedIndex];
171→
172→  const handleQueryChange = useCallback((value: string) => {
173→    setQuery(value);
174→    setSelectedIndex(0);
175→    setActionsOpen(false);
176→  }, []);
177→
178→  const handleFilterChange = useCallback((value: string) => {
179→    setFilterValue(value);
180→    setSelectedIndex(0);
