238→            strokeLinecap="round"
239→            strokeLinejoin="round"
240→          />
241→        </svg>
242→      ),
243→      primaryAction: {
244→        label: 'Move to Trash',
245→        style: 'destructive',
246→        onAction: () => {
247→          setEntries(prev => prev.filter(e => e.id !== entryId));
248→          showHUD({
249→            icon: <CopyHUDIcon />,
250→            title: `Moved "${entryName}" to Trash`,
251→          });
252→        },
253→      },
254→      dismissAction: {
