373→    ],
374→  );
375→
376→  const activeDescendantId =
377→    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;
378→
379→  function renderFileItem(entry: FileEntry, idx: number): ReactNode {
380→    const sizeText = formatFileSize(entry.size);
381→    return (
382→      <ListItem
383→        key={entry.id}
