 963→  function renderQuicklinkItem(entry: QuicklinkEntry, idx: number): ReactNode {
 964→    const accessories = [
 965→      ...(entry.tags?.map(t => ({ tag: t })) ?? []),
 966→      { text: QUICKLINK_TYPE_LABELS[entry.type] },
 967→      {
 968→        text: formatRelativeDate(entry.createdAt, now),
 969→        tooltip: entry.createdAt.toLocaleString(),
 970→      },
 971→    ];
 972→    if (entry.application) {
 973→      accessories.unshift({ text: entry.application });
 974→    }
 975→
 976→    return (
 977→      <ListItem
 978→        key={entry.id}
 979→        index={idx}
 980→        icon={entry.icon ?? getQuicklinkIcon(entry.type)}
 981→        title={entry.name}
 982→        subtitle={entry.link}
 983→        accessories={accessories}
 984→        query={query || undefined}
 985→      />
 986→    );
 987→  }
 988→
 989→  return (
 990→    <>
 991→      <SearchBar
 992→        value={query}
 993→        onChange={handleQueryChange}
 994→        placeholder="Search Quicklinks..."
 995→        activeDescendantId={activeDescendantId}
 996→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
 997→        dropdown={
